metadata.codeSnippet:
import { callMcpSkill } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "5cc326fb-500d-4c17-bc5f-ade143210636";

  const discovery = await callMcpSkill({
    toolId,
    toolName: "search_markets",
    args: {
      query: "Fed will cut rates at the next FOMC meeting",
      status: "open",
      limit: 20
    }
  });

  const candidates = Array.isArray(discovery?.results) ? discovery.results : [];
  if (candidates.length === 0) {
    return {
      step: "probe",
      found: false,
      missingData: ["No matching Kalshi markets returned by search_markets"],
      attemptedBranches: [
        "search_markets(query: Fed will cut rates at the next FOMC meeting, status: open, limit: 20)"
      ],
      stopReason: "No direct candidate available for deterministic selection"
    };
  }

  const ranked = pickTopSemanticCandidates({
    target: "live Kalshi market for whether the Fed will cut rates at the next FOMC meeting",
    candidates,
    requiredTerms: ["fed", "fomc", "rate", "cut"],
    avoidTerms: ["history", "past", "retired"],
    limit: 3
  });

  const shortlist = Array.isArray(ranked) ? ranked : [];
  if (shortlist.length === 0) {
    return {
      step: "decide",
      found: false,
      missingData: ["Semantic targeting returned no acceptable candidates"],
      attemptedBranches: ["search_markets → pickTopSemanticCandidates"],
      stopReason: "Deterministic shortlist could not be formed"
    };
  }

  const best = shortlist[0];
  const resolvedTicker = best?.ticker;
  const resolvedEventTicker = best?.eventTicker;

  if (!resolvedTicker || !resolvedEventTicker) {
    return {
      step: "decide",
      found: false,
      missingData: ["Missing ticker or eventTicker on top semantic candidate"],
      shortlist: shortlist.map((item) => ({
        title: item?.title,
        ticker: item?.ticker,
        eventTicker: item?.eventTicker,
        yesPrice: item?.yesPrice,
        closeTime: item?.closeTime,
        status: item?.status
      })),
      stopReason: "Top candidate lacked required identifiers for execution"
    };
  }

  const market = await callMcpSkill({
    toolId,
    toolName: "get_market",
    args: { ticker: resolvedTicker }
  });

  const event = await callMcpSkill({
    toolId,
    toolName: "get_event",
    args: { eventTicker: resolvedEventTicker }
  });

  const resolvedMarket = market?.market || null;
  const resolvedEvent = event?.event || null;
  const eventMarkets = Array.isArray(event?.markets) ? event.markets : [];

  return {
    step: "execute",
    found: Boolean(resolvedMarket),
    resolvedEvent: resolvedEvent
      ? {
          title: resolvedEvent.title,
          status: resolvedEvent.status,
          category: resolvedEvent.category,
          eventTicker: resolvedEvent.eventTicker
        }
      : null,
    resolvedMarket: resolvedMarket
      ? {
          title: resolvedMarket.title,
          ticker: resolvedMarket.ticker,
          status: resolvedMarket.status,
          yesPrice: resolvedMarket.yesPrice,
          noPrice: resolvedMarket.noPrice,
          closeTime: resolvedMarket.closeTime,
          url: resolvedMarket.url,
          rules: resolvedMarket.rules,
          rulesDetailed: resolvedMarket.rulesDetailed,
          canCloseEarly: resolvedMarket.canCloseEarly,
          earlyCloseCondition: resolvedMarket.earlyCloseCondition
        }
      : null,
    eventMarkets: eventMarkets.map((m) => ({
      title: m.title,
      ticker: m.ticker,
      yesPrice: m.yesPrice,
      noPrice: m.noPrice,
      status: m.status
    })),
    responsePackage: {
      yesPrice: resolvedMarket?.yesPrice,
      noPrice: resolvedMarket?.noPrice,
      closeTime: resolvedMarket?.closeTime,
      marketStatus: resolvedMarket?.status,
      exactSettlementRules: resolvedMarket?.rulesDetailed || resolvedMarket?.rules || null
    }
  };
}

