export async function main() {
  const toolId = "5cc326fb-500d-4c17-bc5f-ade143210636";

  const probe = await callMcpSkill({
    toolId,
    toolName: "search_markets",
    args: {
      query: "KXFEDDECISION",
      category: "Economics",
      status: "open",
      limit: 50,
      maxSeriesScan: 600
    }
  });

  const discovery = probe && Array.isArray(probe?.results) && probe.results.length > 0
    ? probe
    : await callMcpSkill({
        toolId,
        toolName: "search_markets",
        args: {
          query: "Fed will cut rates at the next FOMC meeting",
          status: "open",
          limit: 20,
          category: "Financials"
        }
      });

