    return {
      step: "decide",
      found: false,
      missingData: ["Semantic targeting returned no acceptable candidates"],
      attemptedBranches: ["search_markets → pickTopSemanticCandidates"],
      stopReason: "Deterministic shortlist could not be formed"
    };
