          rulesPrimary: resolvedMarket.rulesPrimary,
          rulesDetailed: resolvedMarket.rulesDetailed,
          canCloseEarly: resolvedMarket.canCloseEarly,
          earlyCloseCondition: resolvedMarket.earlyCloseCondition
        }
