import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

const KALSHI_TOOL_ID = "5cc326fb-500d-4c17-bc5f-ade143210636";

function normText(value) {
  return String(value || "").toLowerCase();
}

function isOpenMarket(market) {
  return normText(market?.status) === "open";
}

function numeric(value) {
  return typeof value === "number" && Number.isFinite(value) ? value : null;
}

function inProbabilityBand(yesPrice) {
  return yesPrice !== null && yesPrice >= 20 && yesPrice <= 80;
}

function tradabilityScore(market) {
  const liquidity = numeric(market?.liquidity) || 0;
  const volume24h = numeric(market?.volume24h) || 0;
  const yesPrice = numeric(market?.yesPrice);
  const spreadPenalty = numeric(market?.spread) || 0;

  let score = 0;
  score += Math.min(liquidity / 2500, 4);
  score += Math.min(volume24h / 1500, 4);
  if (yesPrice !== null && yesPrice >= 20 && yesPrice <= 80) score += 1.5;
  if (liquidity >= 1000) score += 1;
  if (liquidity >= 5000) score += 1;
  score -= Math.min(spreadPenalty / 5, 1);
  return score;
}

export async function main() {
  const discoveryBatch = await callMcpSkillsParallel({
    label: "tariff-discovery-batch",
    calls: [
      {
        key: "probability",
        toolId: KALSHI_TOOL_ID,
