import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "5cc326fb-500d-4c17-bc5f-ade143210636";

  const seriesResult = await callMcpSkill({
    toolId,
    toolName: "get_all_series",
    args: { category: "Climate", limit: 100 },
  });

  const series = Array.isArray(seriesResult?.series) ? seriesResult.series : [];
  const keywords = ["temperature", "temp", "hurricane", "storm", "weather", "rain", "snow", "wind"];
  const shortlistedSeries = series.filter((s) => {
    const title = String(s?.title || "").toLowerCase();
    const ticker = String(s?.ticker || "").toLowerCase();
    const combined = `${title} ${ticker}`;
    return keywords.some((k) => combined.includes(k));
  }).slice(0, 4);

  const inspected = [];
  for (const s of shortlistedSeries) {
    const browse = await callMcpSkill({
      toolId,
      toolName: "browse_series",
      args: { seriesTicker: s.ticker, status: "open", limit: 50 },
    });

    const markets = Array.isArray(browse?.markets) ? browse.markets : [];
    for (const m of markets) {
      inspected.push({
        seriesTitle: s.title,
        seriesTicker: s.ticker,
        ...m,
      });
    }
  }

  const now = Date.now();
  const soonWindowDays = 21;
  const soonWindowMs = soonWindowDays * 24 * 60 * 60 * 1000;

  const enriched = inspected
    .map((m) => {
      const closeTs = Date.parse(m.closeTime);
      const daysToClose = Number.isFinite(closeTs) ? (closeTs - now) / (24 * 60 * 60 * 1000) : null;
      const yesPrice = typeof m.yesPrice === "number" ? m.yesPrice : null;
      const liquidity = typeof m.liquidity === "number" ? m.liquidity : null;
      const volume24h = typeof m.volume24h === "number" ? m.volume24h : null;

      const priceCentering =
        yesPrice === null ? null : Math.min(yesPrice, 100 - yesPrice);

      const crowdedness = (volume24h ?? 0) / Math.max(liquidity ?? 1, 1);

      const openSoonLiquid =
        m.status === "open" &&
        Number.isFinite(closeTs) &&
        closeTs > now &&
        closeTs - now <= soonWindowMs &&
        (liquidity ?? 0) >= 1000 &&
        (volume24h ?? 0) >= 50;

      const notCrowded =
        (volume24h ?? 0) <= 5000 &&
        (priceCentering === null || priceCentering >= 10);

      return {
        seriesTitle: m.seriesTitle,
        seriesTicker: m.seriesTicker,
        title: m.title,
        ticker: m.ticker,
        url: m.url,
        status: m.status,
        yesPrice: m.yesPrice,
        noPrice: m.noPrice,
        liquidity: m.liquidity,
        volume24h: m.volume24h,
        closeTime: m.closeTime,
        daysToClose,
        crowdedness,
        openSoonLiquid,
        notCrowded,
      };
    })
    .filter((m) => m.openSoonLiquid && m.notCrowded);

  enriched.sort((a, b) => {
    const aDays = a.daysToClose ?? 9999;
    const bDays = b.daysToClose ?? 9999;
    if (aDays !== bDays) return aDays - bDays;
    if ((b.liquidity ?? 0) !== (a.liquidity ?? 0)) return (b.liquidity ?? 0) - (a.liquidity ?? 0);
    return (a.crowdedness ?? 9999) - (b.crowdedness ?? 9999);
  });

  const top = enriched.slice(0, 10);

  return {
    fetchedFrom: {
      seriesQuery: "Climate",
      shortlistedSeries: shortlistedSeries.map((s) => ({ title: s.title, ticker: s.ticker, category: s.category })),
    },
    counts: {
      climateSeriesFound: series.length,
      shortlistedSeriesFound: shortlistedSeries.length,
      inspectedMarkets: inspected.length,
      candidateMarkets: enriched.length,
    },
    methodology: {
      openSoonWindowDays: soonWindowDays,
      liquidityFloor: 1000,
      volumeFloor: 50,
      crowdFilter: "volume24h <= 5000 and yesPrice not too close to 0 or 100",
    },
    topCandidates: top,
  };
}

