export async function main() {
  const batch = await callMcpSkillsParallel({
    label: "weather-climate-discovery",
    calls: [
      {
        key: "climate-browse",
        toolId,
        toolName: "browse_category",
        args: {
          category: "Climate",
          status: "open",
          sortBy: "volume_24h",
          limit: 50
        }
      },
      {
        key: "weather-search",
        toolId,
        toolName: "search_markets",
        args: {
          query: "weather",
          status: "open",
          limit: 50
        }
      }
    ]
  });

  const climateBrowse =
    batch.results.find((r) => r.key === "climate-browse" && r.status === "fulfilled")?.value || null;
  const weatherSearch =
    batch.results.find((r) => r.key === "weather-search" && r.status === "fulfilled")?.value || null;

  const climateMarkets = Array.isArray(climateBrowse?.markets) ? climateBrowse.markets : [];
  const weatherMarkets = Array.isArray(weatherSearch?.results) ? weatherSearch.results : [];
