        ticker: market.ticker,
        tradeLimit: 8,
        periodHours: 24,
        candlestickInterval: 60
      }
    });

    const liquidity = await callMcpSkill({
      toolId,
      toolName: "analyze_market_liquidity",
      args: {
        ticker: market.ticker
      }
    });

    analyzed.push({
      title: market.title,
      ticker: market.ticker,
      url: market.url,
      category: market.category,
      yesPrice: market.yesPrice,
      liquidity: market.liquidity,
      volume24h: market.volume24h,
      sentiment: sentiment?.sentiment,
      confidence: sentiment?.confidence,
      priceChange24h: sentiment?.priceChange?.changePercent24h,
      volumeTrend: sentiment?.volumeTrend?.volumeChange,
      liquidityScore: liquidity?.liquidityScore,
      spread: liquidity?.spread?.yesCents ?? liquidity?.spread?.noCents ?? null,
      slippageSimulation: liquidity?.slippageSimulation
    });
  }

  const ranked = analyzed
    .map((x) => ({ ...x, score: scoreOpportunity(x) }))
    .sort((a, b) => b.score - a.score);

  return {
    fetchedAt: climateBrowse?.fetchedAt || weatherSearch?.fetchedAt,
    discovered: {
      climateCount: climateMarkets.length,
      weatherCount: weatherMarkets.length,
      combinedCount: combined.length,
      shortlistedCount: shortlisted.length
    },
    topOpportunities: ranked.slice(0, 5),
    partialFailures: batch.results
      .filter((r) => r.status === "rejected")
      .map((r) => ({ key: r.key, error: r.error })),
    note:
      "This plan uses parallel read-only discovery across different endpoints first, then deterministic semantic targeting and serial follow-up analysis. It covers both weather and climate markets, filters for open and adequately liquid instruments, and ranks by recent sentiment/order-flow signals rather than taking the first results."
  };
}

