  const bullishTape =
    sentiment === "bullish" || sentiment === "strongly_bullish" || (trend !== null && trend > 0) || (candleSlope !== null && candleSlope > 0);
  const bearishTape =
    sentiment === "bearish" || sentiment === "strongly_bearish" || (trend !== null && trend < 0) || (candleSlope !== null && candleSlope < 0);

  let disagreement = false;
  let reason = [];

  if (current !== null) {
    if (current >= 65 && bearishTape) {
      disagreement = true;
      reason.push("headline probability is high but tape is bearish");
    } else if (current <= 35 && bullishTape) {
      disagreement = true;
      reason.push("headline probability is low but tape is bullish");
    }
  }

  const buySide = tradeBias.filter((x) => String(x).toLowerCase().includes("buy")).length;
  const sellSide = tradeBias.filter((x) => String(x).toLowerCase().includes("sell")).length;
  if (buySide > sellSide + 1 && current !== null && current >= 60) {
    disagreement = true;
    reason.push("recent prints lean buying despite already-high probability");
  }
  if (sellSide > buySide + 1 && current !== null && current <= 40) {
    disagreement = true;
    reason.push("recent prints lean selling despite already-low probability");
  }

