      for (const m of entry.value.results) {
        allResults.push({
          source: entry.key,
          ...m,
        });
      }
    }
  }

  const deduped = [];
  const seen = new Set();
  for (const m of allResults) {
    const key = m.ticker || m.url || m.title;
    if (!key || seen.has(key)) continue;
    seen.add(key);
    deduped.push(m);
  }

  const enriched = deduped
    .filter((m) => typeof m.yesPrice === "number" && typeof m.volume24h === "number")
    .map((m) => {
      const distanceFrom50 = Math.abs(m.yesPrice - 50);
      const liquidity = Number.isFinite(m.volume24h) ? m.volume24h : 0;
      return {
        ...m,
        distanceFrom50,
        score: (liquidity / 1000) - distanceFrom50,
      };
    })
    .filter((m) => m.yesPrice >= 35 && m.yesPrice <= 65)
    .sort((a, b) => {
      if (b.volume24h !== a.volume24h) return b.volume24h - a.volume24h;
      if (a.distanceFrom50 !== b.distanceFrom50) return a.distanceFrom50 - b.distanceFrom50;
      return b.score - a.score;
    });

  const shortlist = enriched.slice(0, 5);

  const detailBatch = await callMcpSkillsParallel({
    label: "kalshi-tariff-fed-details",
    calls: shortlist.map((m) => ({
      key: m.ticker,
      toolId,
      toolName: "get_market",
      args: { ticker: m.ticker },
    })),
  });

  const detailsByTicker = {};
  for (const entry of detailBatch.results) {
    if (entry.status === "fulfilled" && entry.value && entry.value.market) {
      detailsByTicker[entry.key] = entry.value.market;
    }
  }

