    const combinedText = `${m.title || ""} ${detail.title || ""} ${detail.rules || ""} ${detail.subtitle || ""}`.toLowerCase();
    const isTariffRelated = combinedText.includes("tariff") || combinedText.includes("trade") || combinedText.includes("china");
    const isFedRelated =
      combinedText.includes("fed") ||
      combinedText.includes("fomc") ||
      combinedText.includes("rate") ||
      combinedText.includes("powell") ||
      combinedText.includes("interest");

    const timeBounded = typeof detail.closeTime === "string" && detail.closeTime.length > 0;
    const clearRules = typeof detail.rulesDetailed === "string"
      ? detail.rulesDetailed.length > 0
      : typeof detail.rules === "string" && detail.rules.length > 0;

    return {
      title: detail.title || m.title,
      ticker: detail.ticker || m.ticker,
      url: detail.url || m.url,
      category: detail.category || m.category,
      yesPrice: detail.yesPrice ?? m.yesPrice,
      liquidity: detail.liquidity ?? m.liquidity ?? null,
      volume24h: detail.volume24h ?? m.volume24h ?? null,
      closeTime: detail.closeTime || m.closeTime || null,
      tradability: typeof (detail.liquidity ?? m.liquidity) === "number"
        ? (detail.liquidity ?? m.liquidity) >= 50000
          ? "high"
          : (detail.liquidity ?? m.liquidity) >= 10000
            ? "moderate"
            : "lower"
        : "unknown",
      timeBounded,
      clearRules,
      theme: isTariffRelated ? "tariff" : isFedRelated ? "fed" : "other",
      suitabilityScore:
        (typeof (detail.liquidity ?? m.liquidity) === "number" ? Math.min((detail.liquidity ?? m.liquidity) / 100000, 5) : 0) +
        (50 - Math.abs((detail.yesPrice ?? m.yesPrice) - 50)) / 10 +
        (timeBounded ? 2 : 0) +
        (clearRules ? 2 : 0),
    };
  });

  const bestForEventDrivenTrades = finalMarkets
    .filter((m) => m.theme !== "other")
    .sort((a, b) => b.suitabilityScore - a.suitabilityScore);

  return {
    note: "This analysis is based on a live tool query from the current session.",
    searchTelemetry: searchBatch.summary,
    detailTelemetry: detailBatch.summary,
    shortlistedMarkets: finalMarkets,
    bestSuitedForEventDrivenTrades: bestForEventDrivenTrades.slice(0, 5),
