export async function main() {
  const toolId = "5cc326fb-500d-4c17-bc5f-ade143210636";

  // 1) Parallel read-only discovery across different endpoints only.
  //    No same-endpoint batching here; shortlist-first exploration will happen after this batch.
  const discoveryBatch = await callMcpSkillsParallel({
    label: "kalshi-portfolio-discovery",
    calls: [
      {
        key: "climateTrending",
        toolId,
        toolName: "discover_trending_markets",
        args: { category: "Climate", limit: 10, sortBy: "volume_24h" }
      },
      {
        key: "sportsTrending",
        toolId,
        toolName: "discover_trending_markets",
        args: { category: "Sports", limit: 10, sortBy: "volume_24h" }
      },
      {
        key: "fedSearch",
        toolId,
        toolName: "search_markets",
        args: { query: "Fed rate cut interest rates", status: "open", limit: 10 }
      },
      {
        key: "tariffSearch",
        toolId,
        toolName: "search_markets",
        args: { query: "tariffs trade duties", status: "open", limit: 10 }
      }
    ]
  });

  const byKey = Object.fromEntries(
    __normalizeToolArrayOutput(discoveryBatch.results).map((entry) => [
      entry.key,
      entry.status === "fulfilled" ? entry.value : null
    ])
  );

  const collectMarkets = (payload) => {
    if (!payload) return [];
    if (Array.isArray(payload.trendingMarkets)) return payload.trendingMarkets;
    if (Array.isArray(payload.results)) return payload.results;
    if (Array.isArray(payload.markets)) return payload.markets;
    return [];
  };

  const candidates = [
    ...collectMarkets(byKey.climateTrending).map((m) => ({ theme: "Climate", discoverySource: "discover_trending_markets", ...m })),
    ...collectMarkets(byKey.sportsTrending).map((m) => ({ theme: "Sports", discoverySource: "discover_trending_markets", ...m })),
    ...collectMarkets(byKey.fedSearch).map((m) => ({ theme: "Fed", discoverySource: "search_markets", ...m })),
    ...collectMarkets(byKey.tariffSearch).map((m) => ({ theme: "Tariff", discoverySource: "search_markets", ...m }))
  ].filter((m) => m && m.ticker);

  // 2) Deterministic semantic targeting to resolve noisy discovery into the most relevant contracts.
  const semanticTargeted = {
    Climate: pickTopSemanticCandidates({
      target: "best current Kalshi climate opportunity with clear contract framing, strong liquidity, and plausible mispricing",
      candidates: candidates.filter((c) => c.theme === "Climate"),
      requiredTerms: ["temperature", "rain", "snow", "weather", "climate"],
      avoidTerms: ["private", "survey", "primary"],
      limit: 3
    }),
    Fed: pickTopSemanticCandidates({
      target: "best current Kalshi Fed policy opportunity with clear contract framing, strong liquidity, and plausible mispricing",
      candidates: candidates.filter((c) => c.theme === "Fed"),
      requiredTerms: ["fed", "rate", "interest", "cpi", "inflation"],
      avoidTerms: ["district", "local", "primary"],
      limit: 3
    }),
    Tariff: pickTopSemanticCandidates({
      target: "best current Kalshi tariff opportunity with clear contract framing, strong liquidity, and plausible mispricing",
      candidates: candidates.filter((c) => c.theme === "Tariff"),
      requiredTerms: ["tariff", "trade", "duties", "china", "imports"],
      avoidTerms: ["primary", "district", "local"],
      limit: 3
    }),
    Sports: pickTopSemanticCandidates({
      target: "best current Kalshi sports opportunity with clear contract framing, strong liquidity, and plausible mispricing",
      candidates: candidates.filter((c) => c.theme === "Sports"),
      requiredTerms: ["nba", "nfl", "mlb", "super bowl", "championship", "sports"],
      avoidTerms: ["weather", "politics", "tariff"],
      limit: 3
    })
  };

  const shortlist = [
    ...semanticTargeted.Climate,
    ...semanticTargeted.Fed,
    ...semanticTargeted.Tariff,
    ...semanticTargeted.Sports
  ].filter((m, idx, arr) => m && m.ticker && arr.findIndex((x) => x.ticker === m.ticker) === idx);

  // 3) Shortlist-first sequential exploration on the same endpoint/tool.
  //    For each shortlisted contract, fetch direct market details, liquidity, and efficiency signals before any final ranking.
  const details = [];
  for (const item of shortlist.slice(0, 8)) {
    const market = await callMcpSkill({
      toolId,
      toolName: "get_market",
      args: { ticker: item.ticker }
    });
    const liquidityAnalysis = await callMcpSkill({
      toolId,
      toolName: "analyze_market_liquidity",
      args: { ticker: item.ticker }
    });
    const efficiencyAnalysis = await callMcpSkill({
      toolId,
      toolName: "check_market_efficiency",
      args: { ticker: item.ticker }
    });
    details.push({
      theme: item.theme,
      discoverySource: item.discoverySource,
      ...item,
      market,
      liquidityAnalysis,
      efficiencyAnalysis
    });
  }

  // 4) If a shortlist item is event-like or needs extra context, resolve via exact event details sequentially.
  //    Keep this bounded; do not fan out same-endpoint calls in parallel.
  const enriched = [];
  for (const item of details) {
    const eventTicker = item.market?.market?.eventTicker || item.eventTicker || item.market?.eventTicker || null;
    let eventDetails = null;
    if (eventTicker) {
      eventDetails = await callMcpSkill({
        toolId,
        toolName: "get_event",
        args: { eventTicker }
      });
    }
    enriched.push({
      ...item,
      eventDetails
    });
  }

  // 5) Local analysis only after read batch completes:
  //    - rule clarity from market rules text
  //    - liquidity quality from analyze_market_liquidity
  //    - mispricing signals from efficiency/liquidity where useful
  const scored = [];
  for (const item of enriched) {
    const market = item.market?.market || {};
    const title = market.title || item.title || "";
    const rules = market.rulesDetailed || market.rules || "";
    const liquidity = typeof market.liquidity === "number" ? market.liquidity : 0;
    const volume24h = typeof market.volume24h === "number" ? market.volume24h : 0;
    const yesPrice = typeof market.yesPrice === "number" ? market.yesPrice : null;
    const noPrice = typeof market.noPrice === "number" ? market.noPrice : null;
    const liq = item.liquidityAnalysis || {};
    const eff = item.efficiencyAnalysis || {};

    const ruleClarity =
      rules && rules.length > 0
        ? (rules.length > 800 ? "detailed" : "usable")
        : "missing";

    const liquidityQuality =
      (liq.liquidityScore >= 80 ? "excellent" :
      liq.liquidityScore >= 60 ? "good" :
      liq.liquidityScore >= 40 ? "moderate" :
      liq.liquidityScore > 0 ? "poor" :
      liquidity >= 50000 ? "excellent" :
      liquidity >= 10000 ? "good" :
      liquidity >= 3000 ? "moderate" :
      liquidity > 0 ? "poor" : "unknown");

    const mispricingSignal = eff.efficiency?.rating === "exploitable" || eff.efficiency?.rating === "poor"
      ? "watch"
      : (typeof eff.efficiency?.vig === "number" && eff.efficiency.vig >= 4 ? "watch" : "weak");

    const baseScore =
      Math.log10((liq.depth?.totalDepthUsd || liquidity) + 1) * 2 +
      Math.log10(volume24h + 1) +
      (ruleClarity === "detailed" ? 1.5 : ruleClarity === "usable" ? 1 : 0) +
      (liquidityQuality === "excellent" ? 1.5 : liquidityQuality === "good" ? 1 : liquidityQuality === "moderate" ? 0.5 : 0) +
      (mispricingSignal === "watch" ? 1 : 0);

    scored.push({
      theme: item.theme,
      title,
      ticker: market.ticker || item.ticker,
      url: market.url || item.url,
      category: market.category || item.category || item.theme,
      yesPrice,
      noPrice,
      liquidity,
      volume24h,
      closeTime: market.closeTime || item.closeTime || null,
      ruleClarity,
      liquidityQuality,
      mispricingSignal,
      liquidityAnalysis: liq,
      efficiencyAnalysis: eff,
      score: baseScore,
      rulesSnippet: typeof rules === "string" ? rules.slice(0, 240) : null,
      crossVenueValidationNeeded:
        item.theme === "Fed" || item.theme === "Tariff" || item.theme === "Sports"
    });
  }

  scored.sort((a, b) => b.score - a.score);

  const portfolioMap = {
    Climate: scored.find((x) => x.theme === "Climate") || null,
    Fed: scored.find((x) => x.theme === "Fed") || null,
    Tariff: scored.find((x) => x.theme === "Tariff") || null,
    Sports: scored.find((x) => x.theme === "Sports") || null
  };

  // 6) Explicit cross-venue validation notes:
  //    - Fed and Tariff: Polymarket contributor validation
  //    - Sports: Odds API contributor validation
  //    - Climate: validate only if the contract wording is ambiguous or rule-heavy; prefer Polymarket contributor if cross-venue check is needed
  const crossVenueValidation = [
    portfolioMap.Climate ? {
      theme: "Climate",
      ticker: portfolioMap.Climate.ticker,
      title: portfolioMap.Climate.title,
      contributor: "Polymarket contributor",
      reason: "Only if the climate contract wording or resolution rules are ambiguous",
      note: portfolioMap.Climate.ruleClarity
    } : null,
    portfolioMap.Fed ? {
      theme: "Fed",
      ticker: portfolioMap.Fed.ticker,
      title: portfolioMap.Fed.title,
      contributor: "Polymarket contributor",
      reason: "Direct cross-venue check recommended for policy/rates contracts",
      note: portfolioMap.Fed.efficiencyAnalysis?.efficiency?.rating || portfolioMap.Fed.mispricingSignal
    } : null,
    portfolioMap.Tariff ? {
      theme: "Tariff",
      ticker: portfolioMap.Tariff.ticker,
      title: portfolioMap.Tariff.title,
      contributor: "Polymarket contributor",
      reason: "Direct cross-venue check recommended for trade/tariff resolution wording",
      note: portfolioMap.Tariff.efficiencyAnalysis?.efficiency?.rating || portfolioMap.Tariff.mispricingSignal
    } : null,
    portfolioMap.Sports ? {
      theme: "Sports",
      ticker: portfolioMap.Sports.ticker,
      title: portfolioMap.Sports.title,
      contributor: "Odds API contributor",
      reason: "Use sports-specific external validation for matchup/event alignment",
      note: portfolioMap.Sports.efficiencyAnalysis?.efficiency?.rating || portfolioMap.Sports.mispricingSignal
    } : null
  ].filter(Boolean);

  return {
    plan: {
      step1: "Parallel discovery across different Kalshi endpoints only",
      step2: "Deterministic semantic targeting of noisy candidates",
      step3: "Sequential shortlist-first contract detail fetch for rule clarity",
      step4: "Optional sequential event resolution for added context",
      step5: "Local scoring on rule clarity, liquidity quality, and mispricing signals",
      step6: "Explicit cross-venue validation annotations by contract"
    },
    portfolioMap,
    selectedContracts: scored.slice(0, 4),
    crossVenueValidation,
    discoveryTelemetry: discoveryBatch.summary,
    partialFailures: discoveryBatch.results
      .filter((entry) => entry.status === "rejected")
      .map((entry) => ({ key: entry.key, error: entry.error })),
    note: "This plan is structured for execution before any live fetches beyond the bounded discovery and shortlist follow-ups."
  };
}

